const nowKarachi = $now.setZone('Asia/Karachi');
const weekEnding = nowKarachi.minus({ days: 1 }); // Saturday just gone
const weekStart = weekEnding.minus({ days: 6 }); // Sunday before that
return [{ json: {
  weekStartStr: weekStart.toFormat('yyyy-MM-dd'),
  weekEndingStr: weekEnding.toFormat('yyyy-MM-dd')
} }];

function toDateStr(raw) {
  if (raw === null || raw === undefined || raw === '') return null;
  const s = String(raw).trim();
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);
  const d = new Date(s);
  if (isNaN(d.getTime())) return null;
  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd}`;
}

// RISK_TIER THRESHOLDS -- not specified in the handoff/brief, this is an
// assumption. Change here if you want different cutoffs:
//   RED_Flag_Count_Week >= 3  -> HIGH
//   RED_Flag_Count_Week >= 1  -> MEDIUM
//   else                      -> LOW

const window = $('Compute Week Window').first().json;
const weekStart = window.weekStartStr;
const weekEnd = window.weekEndingStr;

const tripRows = $('Read Trip_Data').all().map(i => i.json);

const inWindow = tripRows.filter(r => {
  const d = toDateStr(r.Trip_Date);
  return d && d >= weekStart && d <= weekEnd;
});

const byDriver = {};
for (const r of inWindow) {
  const id = r.Driver_ID;
  if (!id) continue;
  if (!byDriver[id]) {
    byDriver[id] = {
      Driver_ID: id,
      Total_Trips_Week: 0,
      Total_GPS_Km_Week: 0,
      Total_Claimed_Km_Week: 0,
      Total_Variance_Km_Week: 0,
      Total_Variance_PKR_Week: 0,
      variancePctSum: 0,
      RED_Flag_Count_Week: 0,
      AMBER_Flag_Count_Week: 0
    };
  }
  const d = byDriver[id];
  d.Total_Trips_Week += 1;
  d.Total_GPS_Km_Week += Number(r.GPS_Km) || 0;
  d.Total_Claimed_Km_Week += Number(r.Claimed_Km) || 0;
  d.Total_Variance_Km_Week += Number(r.Variance_Km) || 0;
  d.Total_Variance_PKR_Week += Number(r.Variance_PKR) || 0;
  d.variancePctSum += Number(r.Variance_Percent) || 0;
  if (r.Flag_Colour === 'RED') d.RED_Flag_Count_Week += 1;
  if (r.Flag_Colour === 'AMBER') d.AMBER_Flag_Count_Week += 1;
}

let drivers = Object.values(byDriver).map(d => {
  const avgPct = d.Total_Trips_Week > 0 ? d.variancePctSum / d.Total_Trips_Week : 0;
  let riskTier = 'LOW';
  if (d.RED_Flag_Count_Week >= 3) riskTier = 'HIGH';
  else if (d.RED_Flag_Count_Week >= 1) riskTier = 'MEDIUM';
  return {
    Week_Ending_Date: weekEnd,
    Driver_ID: d.Driver_ID,
    Total_Trips_Week: d.Total_Trips_Week,
    Total_GPS_Km_Week: Number(d.Total_GPS_Km_Week.toFixed(2)),
    Total_Claimed_Km_Week: Number(d.Total_Claimed_Km_Week.toFixed(2)),
    Total_Variance_Km_Week: Number(d.Total_Variance_Km_Week.toFixed(2)),
    Total_Variance_PKR_Week: Number(d.Total_Variance_PKR_Week.toFixed(2)),
    Avg_Variance_Percent_Week: Number(avgPct.toFixed(2)),
    RED_Flag_Count_Week: d.RED_Flag_Count_Week,
    AMBER_Flag_Count_Week: d.AMBER_Flag_Count_Week,
    Risk_Tier: riskTier
  };
});

// Rank by Total_Variance_PKR_Week descending, per project owner confirmation.
drivers.sort((a, b) => b.Total_Variance_PKR_Week - a.Total_Variance_PKR_Week);
drivers = drivers.map((d, idx) => ({ ...d, Fleet_Rank_This_Week: idx + 1 }));

const top5 = drivers.slice(0, 5);
const totalFleetVariancePKR = drivers.reduce((s, d) => s + d.Total_Variance_PKR_Week, 0);

return [{ json: {
  weekStart,
  weekEnd,
  drivers,
  top5,
  totalFleetVariancePKR: Number(totalFleetVariancePKR.toFixed(2)),
  driverCount: drivers.length
} }];

const data = $('Aggregate Driver Weekly Stats').first().json;

const lines = data.top5.map((d, i) =>
  `${i + 1}. *${d.Driver_ID}* — PKR ${d.Total_Variance_PKR_Week.toLocaleString()} variance (${d.Avg_Variance_Percent_Week}% avg, ${d.RED_Flag_Count_Week} RED trip(s), Risk: ${d.Risk_Tier})`
).join('\n');

const text = `*Weekly Fuel Variance Report*\nWeek: ${data.weekStart} to ${data.weekEnd}\nTotal fleet variance: PKR ${data.totalFleetVariancePKR.toLocaleString()} across ${data.driverCount} driver(s)\n\n*Top 5 Variance Drivers:*\n${lines}`;

return [{ json: { text } }];
